# Fill in the missing parts for Pre-LN and Post-LN

class PreLNBlock(nn.Module):
    def forward(self, x):
        x = x + self.sublayer(nn.functional.layer_norm(x, x.shape[-1:]))  # LayerNorm before sublayer
        return x

class PostLNBlock(nn.Module):
    def forward(self, x):
        x = nn.functional.layer_norm(x + self.sublayer(x), x.shape[-1:])  # LayerNorm after residual
        return x

print("Pre-LN: x = x + Sublayer(LayerNorm(x))")
print("Post-LN: x = LayerNorm(x + Sublayer(x))")
